const el = {};
const storm3d = {
  ready: false,
  canvas: null,
  ctx: null,
  base: null,
  baseCtx: null,
  trail: null,
  trailCtx: null,
  width: 0,
  height: 0,
  dpr: 1,
  particles: [],
  particleCount: 2800,
  lastState: null,
  pendingState: null,
  animationId: null,
  cam: { lon: 129, lat: 33, latSpan: 44, zoom: 1 },
  storm: { lon: 129, lat: 25, strength: 0.5, radius: 3.4 },
  interaction: { dragging: false, lastX: 0, lastY: 0, pointerActive: false, pointerLon: 127, pointerLat: 35 },
};

const STORM3D_DEFAULT_CAM = { lon: 129, lat: 33, latSpan: 44, zoom: 1 };
const MAP_BOUNDS = { lon0: 96, lon1: 154, lat0: 8, lat1: 54 };

function clamp(min, max, value) {
  return Math.min(max, Math.max(min, value));
}

function has(id) {
  return selected.has(id);
}

function getSelectedFactors() {
  return factors.filter((factor) => selected.has(factor.id));
}

function byId(id) {
  return document.getElementById(id);
}

function collectElements() {
  Object.assign(el, {
    quizList: byId('quizList'),
    stormStage: byId('stormStage'),
    powerValue: byId('powerValue'),
    powerLabel: byId('powerLabel'),
    simulateButton: byId('simulateButton'),
    resetButton: byId('resetButton'),
    intensityMetric: byId('intensityMetric'),
    intensityMeter: byId('intensityMeter'),
    damageMetric: byId('damageMetric'),
    damageMeter: byId('damageMeter'),
    scoreMetric: byId('scoreMetric'),
    analysisBox: byId('analysisBox'),
    resultScreen: byId('resultScreen'),
    resultTitle: byId('resultTitle'),
    resultSummary: byId('resultSummary'),
    resultScore: byId('resultScore'),
    resultPower: byId('resultPower'),
    resultDamage: byId('resultDamage'),
    riskList: byId('riskList'),
    answerReview: byId('answerReview'),
    storm3dCanvas: byId('storm3dCanvas'),
    storm3dTitle: byId('storm3dTitle'),
    storm3dSummary: byId('storm3dSummary'),
    storm3dImpact: byId('storm3dImpact'),
    impactRing: byId('impactRing'),
  });
}

function renderFactorButtons() {
  const createButton = (factor) => {
    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'factor-button';
    button.dataset.factorId = factor.id;
    button.setAttribute('aria-pressed', 'false');
    button.innerHTML = `
      <span class="factor-icon" aria-hidden="true">${factor.icon}</span>
      <span class="factor-text">
        <strong>${factor.label}</strong>
        <small>${factor.summary}</small>
      </span>
      <span class="factor-status">선택</span>
    `;
    button.addEventListener('click', () => toggleFactor(factor.id));
    return button;
  };

  const shuffled = factors.slice();
  for (let i = shuffled.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  shuffled.forEach((factor) => {
    el.quizList.appendChild(createButton(factor));
  });
}

function getSynergies() {
  const synergies = [];

  if (has('sst') && has('oceanHeat') && has('lowShear')) {
    synergies.push({ label: '급격한 강화 조건', value: 8, reason: '따뜻한 해수·깊은 열용량·낮은 시어가 동시에 선택되었습니다.' });
  }

  if (has('convergence') && has('outflow')) {
    synergies.push({ label: '순환 환기 보너스', value: 5, reason: '하층 수렴과 상층 발산이 연결되어 상승 운동이 강화됩니다.' });
  }

  if (has('strongShear') && has('dryAir')) {
    synergies.push({ label: '구조 붕괴 페널티', value: -6, reason: '강한 연직 시어와 건조 공기가 함께 태풍의 대칭 구조를 약화합니다.' });
  }

  if (has('landfall') && has('friction')) {
    synergies.push({ label: '내륙 감쇠 페널티', value: -7, reason: '육지 상륙과 지형 마찰이 함께 하층 순환을 빠르게 약화합니다.' });
  }

  return synergies;
}

function calculateState() {
  const selectedFactors = factors.filter((factor) => selected.has(factor.id));
  const factorSum = selectedFactors.reduce((sum, factor) => sum + factor.weight, 0);
  const synergies = getSynergies();
  const synergySum = synergies.reduce((sum, item) => sum + item.value, 0);
  const power = clamp(5, 100, Math.round(basePower + factorSum + synergySum));

  const windRisk = clamp(0, 100, Math.round(
    power * 0.62 +
    (has('sst') ? 8 : 0) +
    (has('lowShear') ? 5 : 0) -
    (has('strongShear') ? 8 : 0) -
    (has('landfall') ? 7 : 0)
  ));

  const rainRisk = clamp(0, 100, Math.round(
    power * 0.45 +
    (has('moistAir') ? 12 : 0) +
    (has('convergence') ? 8 : 0) +
    (has('landfall') ? 4 : 0) -
    (has('dryAir') ? 10 : 0)
  ));

  const surgeRisk = clamp(0, 100, Math.round(
    power * 0.36 +
    (has('oceanHeat') ? 8 : 0) +
    (has('outflow') ? 5 : 0) -
    (has('coldWater') ? 8 : 0)
  ));

  const koreaDamage = clamp(0, 100, Math.round(windRisk * 0.46 + rainRisk * 0.34 + surgeRisk * 0.20));
  const weaknessCount = selectedFactors.filter((factor) => factor.type === 'weakness').length;
  const weakeningEducationBonus = Math.min(80, weaknessCount * 12);
  const score = clamp(0, 1000, Math.round(1000 - koreaDamage * 9.2 - Math.max(0, power - 70) * 1.8 + weakeningEducationBonus));

  return {
    selectedFactors,
    factorSum,
    synergies,
    synergySum,
    power,
    windRisk,
    rainRisk,
    surgeRisk,
    koreaDamage,
    score,
  };
}

function getPowerLabel(power) {
  if (power >= 86) return '초강력';
  if (power >= 70) return '매우 강함';
  if (power >= 54) return '강함';
  if (power >= 34) return '보통';
  return '약함';
}

function getDamageLabel(damage) {
  if (damage >= 80) return '매우 큼';
  if (damage >= 62) return '큼';
  if (damage >= 42) return '보통';
  if (damage >= 22) return '낮음';
  return '매우 낮음';
}

function getDamageTone(damage) {
  if (damage >= 80) return '대형 사고예요! 강풍·호우·해안 위험을 한꺼번에 키워버렸네요. 이게… 최선이었나요?';
  if (damage >= 62) return '저런, 태풍이 더 강해졌어요. 한반도가 정통으로 맞게 생겼는데요? 강화 조건을 좀 줄여보죠.';
  if (damage >= 42) return '딱 애매한 중간. 한반도가 안심하긴 아직 일러요. 한 끗만 더 손봐볼까요?';
  if (damage >= 22) return '오, 제법인데요? 태풍 기세를 한풀 꺾었어요. 조금만 더 밀어붙여 보세요.';
  return '완벽해요! 태풍이 힘 한번 못 쓰고 스르륵 사그라들었어요. 한반도가 박수칩니다.';
}

function getStorm3dTone(damage) {
  if (damage >= 80) return { color: 0xff5544, title: '헉, 역대급 괴물 태풍 완성!' };
  if (damage >= 62) return { color: 0xff665f, title: '저런… 태풍이 더 강해졌어요' };
  if (damage >= 42) return { color: 0xffbd6d, title: '음~ 어중간한 태풍이 됐네요' };
  if (damage >= 22) return { color: 0x9fe7c0, title: '오, 좀 약해졌는데요?' };
  return { color: 0x7dffca, title: '굿! 태풍을 잘 말려버렸어요' };
}

function setStorm3dCopy(state) {
  if (!el.storm3dTitle || !el.storm3dSummary || !el.storm3dImpact) return;

  if (!state) {
    el.storm3dTitle.textContent = '시뮬레이션 대기 중';
    el.storm3dSummary.textContent = '카드를 고르고 결과 시뮬레이션을 실행하면 실제 바람 흐름 지도에 한반도 주변 태풍이 표시됩니다.';
    el.storm3dImpact.textContent = '--';
    return;
  }

  const tone = getStorm3dTone(state.koreaDamage);
  el.storm3dTitle.textContent = tone.title;
  el.storm3dSummary.textContent = `강풍 ${state.windRisk} · 호우 ${state.rainRisk} · 해안 ${state.surgeRisk} (각 100점 만점). 이번 판 점수는 ${state.score}점!`;
  el.storm3dImpact.textContent = `${state.koreaDamage}/100`;
}

function projScale() {
  const pxPerLat = (storm3d.height / storm3d.cam.latSpan) * storm3d.cam.zoom;
  const pxPerLon = pxPerLat * Math.cos(storm3d.cam.lat * Math.PI / 180);
  return { pxPerLat, pxPerLon };
}

function projectLonLat(lon, lat, sc) {
  const s = sc || projScale();
  const x = storm3d.width / 2 + (lon - storm3d.cam.lon) * s.pxPerLon;
  const y = storm3d.height / 2 - (lat - storm3d.cam.lat) * s.pxPerLat;
  return [x, y];
}

function unprojectXY(px, py) {
  const s = projScale();
  const lon = storm3d.cam.lon + (px - storm3d.width / 2) / s.pxPerLon;
  const lat = storm3d.cam.lat - (py - storm3d.height / 2) / s.pxPerLat;
  return [lon, lat];
}

function clampCamera() {
  const B = MAP_BOUNDS;
  const cam = storm3d.cam;
  const aspect = storm3d.width / Math.max(1, storm3d.height);
  const dataLat = B.lat1 - B.lat0;
  const dataLon = B.lon1 - B.lon0;
  for (let pass = 0; pass < 2; pass += 1) {
    const cosl = Math.cos(cam.lat * Math.PI / 180) || 1;
    const minZoom = Math.max(cam.latSpan / dataLat, (cam.latSpan * aspect / cosl) / dataLon);
    cam.zoom = Math.max(cam.zoom, minZoom);
    const visLat = cam.latSpan / cam.zoom;
    const visLon = visLat * aspect / cosl;
    cam.lat = visLat >= dataLat ? (B.lat0 + B.lat1) / 2 : clamp(B.lat0 + visLat / 2, B.lat1 - visLat / 2, cam.lat);
    cam.lon = visLon >= dataLon ? (B.lon0 + B.lon1) / 2 : clamp(B.lon0 + visLon / 2, B.lon1 - visLon / 2, cam.lon);
  }
}

function sampleWind(lon, lat) {
  const m = WIND_META;
  const fx = lon - m.lon0;
  const fy = m.lat1 - lat;
  if (fx < 0 || fy < 0 || fx > m.nx - 1 || fy > m.ny - 1) return [0, 0];
  const x0 = Math.floor(fx);
  const y0 = Math.floor(fy);
  const x1 = Math.min(x0 + 1, m.nx - 1);
  const y1 = Math.min(y0 + 1, m.ny - 1);
  const tx = fx - x0;
  const ty = fy - y0;
  const i00 = y0 * m.nx + x0;
  const i10 = y0 * m.nx + x1;
  const i01 = y1 * m.nx + x0;
  const i11 = y1 * m.nx + x1;
  const u = (WIND_U[i00] * (1 - tx) + WIND_U[i10] * tx) * (1 - ty) + (WIND_U[i01] * (1 - tx) + WIND_U[i11] * tx) * ty;
  const v = (WIND_V[i00] * (1 - tx) + WIND_V[i10] * tx) * (1 - ty) + (WIND_V[i01] * (1 - tx) + WIND_V[i11] * tx) * ty;
  return [u, v];
}

function windField(lon, lat) {
  let [u, v] = sampleWind(lon, lat);
  const cosl = Math.cos(lat * Math.PI / 180) || 1;

  const s = storm3d.storm;
  const dx = (lon - s.lon) * cosl;
  const dy = lat - s.lat;
  const r = Math.hypot(dx, dy);
  if (r > 1e-3) {
    // 북반구 저기압: 반시계방향(사이클론) 회전, 눈 부근은 약하고 눈벽 반경에서 최대
    const vt = s.strength * 34 * (r / s.radius) * Math.exp(-(r * r) / (s.radius * s.radius));
    u += -dy / r * vt;
    v += dx / r * vt;
    // 나선형 유입: 중심으로 약하게 빨려들어 동심원이 아닌 소용돌이가 되도록
    const inflow = vt * 0.22;
    u += -dx / r * inflow;
    v += -dy / r * inflow;
    // 북동진 유도(태풍 전향): 중심 주변에 약한 북동 성분 추가
    const steer = s.strength * 6 * Math.exp(-(r * r) / (s.radius * s.radius * 2.4));
    u += steer * 0.5;
    v += steer * 0.7;
  }
  return [u, v];
}

function readPalette() {
  const cs = getComputedStyle(document.documentElement);
  const v = (name, fb) => {
    const x = cs.getPropertyValue(name).trim();
    return x || fb;
  };
  const trip = (name, fb) => {
    const x = cs.getPropertyValue(name).trim();
    if (!x) return fb;
    const p = x.split(',').map((n) => parseFloat(n));
    return (p.length === 3 && p.every((n) => !Number.isNaN(n))) ? p : fb;
  };
  storm3d.palette = {
    oceanTop: v('--map-ocean-top', '#0e2742'),
    oceanBottom: v('--map-ocean-bottom', '#07182c'),
    land: v('--map-land', '#16223a'),
    coast: v('--map-coast', 'rgba(205,228,255,0.6)'),
    grid: v('--map-grid', 'rgba(150,180,220,0.10)'),
    marker: v('--map-marker', 'rgba(125,255,202,0.9)'),
    windLow: trip('--wind-low', [46, 92, 196]),
    windMid: trip('--wind-mid', [72, 212, 160]),
    windHigh: trip('--wind-high', [236, 240, 150]),
  };
}

function windColor(speed) {
  const t = clamp(0, 1, speed / 30);
  const p = storm3d.palette || { windLow: [46, 92, 196], windMid: [72, 212, 160], windHigh: [236, 240, 150] };
  let a;
  let b;
  let k;
  if (t < 0.5) {
    a = p.windLow;
    b = p.windMid;
    k = t / 0.5;
  } else {
    a = p.windMid;
    b = p.windHigh;
    k = (t - 0.5) / 0.5;
  }
  const r = a[0] + (b[0] - a[0]) * k;
  const g = a[1] + (b[1] - a[1]) * k;
  const bl = a[2] + (b[2] - a[2]) * k;
  return `rgb(${r | 0},${g | 0},${bl | 0})`;
}

function drawBaseMap() {
  const ctx = storm3d.baseCtx;
  if (!ctx) return;
  if (!storm3d.palette) readPalette();
  const pal = storm3d.palette;
  const w = storm3d.width;
  const h = storm3d.height;
  const sc = projScale();

  const ocean = ctx.createLinearGradient(0, 0, 0, h);
  ocean.addColorStop(0, pal.oceanTop);
  ocean.addColorStop(1, pal.oceanBottom);
  ctx.fillStyle = ocean;
  ctx.fillRect(0, 0, w, h);

  ctx.fillStyle = pal.land;
  LAND_POLYS.forEach((poly) => {
    ctx.beginPath();
    for (let i = 0; i < poly.length; i += 1) {
      const [x, y] = projectLonLat(poly[i][0], poly[i][1], sc);
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    }
    ctx.closePath();
    ctx.fill();
  });

  ctx.strokeStyle = pal.grid;
  ctx.lineWidth = 1;
  for (let lon = 90; lon <= 170; lon += 10) {
    const [x0, y0] = projectLonLat(lon, 0, sc);
    const [x1, y1] = projectLonLat(lon, 70, sc);
    ctx.beginPath();
    ctx.moveTo(x0, y0);
    ctx.lineTo(x1, y1);
    ctx.stroke();
  }
  for (let lat = 0; lat <= 70; lat += 10) {
    const [x0, y0] = projectLonLat(80, lat, sc);
    const [x1, y1] = projectLonLat(175, lat, sc);
    ctx.beginPath();
    ctx.moveTo(x0, y0);
    ctx.lineTo(x1, y1);
    ctx.stroke();
  }

  ctx.strokeStyle = pal.coast;
  ctx.lineWidth = 1.1;
  COAST_LINES.forEach((line) => {
    ctx.beginPath();
    for (let i = 0; i < line.length; i += 1) {
      const [x, y] = projectLonLat(line[i][0], line[i][1], sc);
      if (i === 0) ctx.moveTo(x, y);
      else ctx.lineTo(x, y);
    }
    ctx.stroke();
  });

  // 한반도 위치 표시(작고 은은하게)
  const [kx, ky] = projectLonLat(127.8, 36.4, sc);
  ctx.fillStyle = pal.marker;
  ctx.beginPath();
  ctx.arc(kx, ky, 4, 0, Math.PI * 2);
  ctx.fill();
}

function resizeStorm3d() {
  if (!storm3d.canvas) return;
  readPalette();
  const rect = storm3d.canvas.getBoundingClientRect();
  const dpr = Math.min(window.devicePixelRatio || 1, 2);
  storm3d.dpr = dpr;
  storm3d.width = Math.max(1, Math.floor(rect.width));
  storm3d.height = Math.max(1, Math.floor(rect.height));
  [storm3d.canvas, storm3d.base, storm3d.trail].forEach((c) => {
    if (c) {
      c.width = storm3d.width * dpr;
      c.height = storm3d.height * dpr;
    }
  });
  [storm3d.ctx, storm3d.baseCtx, storm3d.trailCtx].forEach((c) => {
    if (c) c.setTransform(dpr, 0, 0, dpr, 0, 0);
  });
  clampCamera();
  drawBaseMap();
  if (storm3d.trailCtx) storm3d.trailCtx.clearRect(0, 0, storm3d.width, storm3d.height);
}

function seedParticle(p) {
  const [lon, lat] = unprojectXY(Math.random() * storm3d.width, Math.random() * storm3d.height);
  p.lon = lon;
  p.lat = lat;
  p.age = Math.floor(Math.random() * 100);
}

function clearTrail() {
  if (storm3d.trailCtx) storm3d.trailCtx.clearRect(0, 0, storm3d.width, storm3d.height);
}

function bindStorm3dInteractions() {
  const canvas = storm3d.canvas;
  if (!canvas) return;

  canvas.addEventListener('pointerdown', (event) => {
    storm3d.interaction.dragging = true;
    storm3d.interaction.lastX = event.clientX;
    storm3d.interaction.lastY = event.clientY;
    canvas.setPointerCapture?.(event.pointerId);
  });

  canvas.addEventListener('pointermove', (event) => {
    const rect = canvas.getBoundingClientRect();
    const [lon, lat] = unprojectXY(event.clientX - rect.left, event.clientY - rect.top);
    storm3d.interaction.pointerLon = lon;
    storm3d.interaction.pointerLat = lat;
    storm3d.interaction.pointerActive = true;
    canvas.dataset.pointer = `${lon.toFixed(1)},${lat.toFixed(1)}`;
    if (storm3d.interaction.dragging) {
      const sc = projScale();
      storm3d.cam.lon -= (event.clientX - storm3d.interaction.lastX) / sc.pxPerLon;
      storm3d.cam.lat += (event.clientY - storm3d.interaction.lastY) / sc.pxPerLat;
      clampCamera();
      storm3d.interaction.lastX = event.clientX;
      storm3d.interaction.lastY = event.clientY;
      drawBaseMap();
      clearTrail();
    }
  });

  canvas.addEventListener('pointerup', (event) => {
    storm3d.interaction.dragging = false;
    canvas.releasePointerCapture?.(event.pointerId);
  });

  canvas.addEventListener('pointerleave', () => {
    storm3d.interaction.dragging = false;
    storm3d.interaction.pointerActive = false;
  });

  canvas.addEventListener('wheel', (event) => {
    event.preventDefault();
    storm3d.cam.zoom = clamp(0.7, 3.6, storm3d.cam.zoom * (event.deltaY > 0 ? 0.9 : 1.1));
    clampCamera();
    canvas.dataset.zoom = storm3d.cam.zoom.toFixed(2);
    drawBaseMap();
    clearTrail();
  }, { passive: false });
}

function animateStorm3d() {
  if (!storm3d.ready || !storm3d.ctx) return;
  const liveRect = storm3d.canvas.getBoundingClientRect();
  if (Math.floor(liveRect.width) !== storm3d.width || Math.floor(liveRect.height) !== storm3d.height) {
    resizeStorm3d();
  }
  const ctx = storm3d.ctx;
  const tctx = storm3d.trailCtx;
  const w = storm3d.width;
  const h = storm3d.height;
  const sc = projScale();
  const state = storm3d.lastState;
  const energy = state ? 0.7 + (state.power / 100) * 0.9 : 0.7;

  tctx.globalCompositeOperation = 'destination-out';
  tctx.fillStyle = 'rgba(0,0,0,0.05)';
  tctx.fillRect(0, 0, w, h);
  tctx.globalCompositeOperation = 'source-over';
  tctx.lineWidth = 1.05;

  const particles = storm3d.particles;
  for (let k = 0; k < particles.length; k += 1) {
    const p = particles[k];
    const [u, v] = windField(p.lon, p.lat);
    const speed = Math.hypot(u, v);
    const [x0, y0] = projectLonLat(p.lon, p.lat, sc);
    const cosl = Math.cos(p.lat * Math.PI / 180) || 1;
    p.lon += (u / (111.32 * cosl)) * energy * 0.9;
    p.lat += (v / 111.32) * energy * 0.9;
    p.age += 1;
    const [x1, y1] = projectLonLat(p.lon, p.lat, sc);
    if (p.age > 100 || speed < 0.35 || x1 < -30 || x1 > w + 30 || y1 < -30 || y1 > h + 30) {
      seedParticle(p);
      continue;
    }
    tctx.strokeStyle = windColor(speed);
    tctx.globalAlpha = clamp(0.22, 0.95, 0.32 + speed / 26);
    tctx.beginPath();
    tctx.moveTo(x0, y0);
    tctx.lineTo(x1, y1);
    tctx.stroke();
  }
  tctx.globalAlpha = 1;

  ctx.clearRect(0, 0, w, h);
  ctx.drawImage(storm3d.base, 0, 0, w, h);
  ctx.drawImage(storm3d.trail, 0, 0, w, h);

  if (storm3d.canvas) storm3d.canvas.dataset.frame = String(Math.round(performance.now()));
  storm3d.animationId = window.setTimeout(animateStorm3d, 33);
}

function updateStorm3dScene(state) {
  setStorm3dCopy(state);
  storm3d.pendingState = state;
  if (!storm3d.ready) return;
  storm3d.lastState = state;
  storm3d.pendingState = null;
  const power = state.power / 100;
  const dmg = state.koreaDamage / 100;
  storm3d.storm.lat = 25.5 + dmg * 7;
  storm3d.storm.lon = 128.5 - dmg * 1.6;
  storm3d.storm.strength = 0.5 + power * 1.8;
  storm3d.storm.radius = 3.4 + power * 3.4;
}

function resetStorm3dScene() {
  setStorm3dCopy(null);
  storm3d.pendingState = null;
  storm3d.lastState = null;
  storm3d.storm.lat = 25;
  storm3d.storm.lon = 129;
  storm3d.storm.strength = 0.5;
  storm3d.storm.radius = 3.4;
  storm3d.interaction.dragging = false;
  storm3d.interaction.pointerActive = false;
  storm3d.cam = { ...STORM3D_DEFAULT_CAM };
  if (storm3d.ready) clampCamera();
  if (storm3d.ready) {
    drawBaseMap();
    clearTrail();
  }
}

function initStorm3dScene() {
  if (typeof window === 'undefined' || !el.storm3dCanvas || storm3d.ready) return;

  storm3d.canvas = el.storm3dCanvas;
  storm3d.ctx = storm3d.canvas.getContext('2d');
  storm3d.base = document.createElement('canvas');
  storm3d.baseCtx = storm3d.base.getContext('2d');
  storm3d.trail = document.createElement('canvas');
  storm3d.trailCtx = storm3d.trail.getContext('2d');

  storm3d.particles = [];
  for (let i = 0; i < storm3d.particleCount; i += 1) storm3d.particles.push({ lon: 0, lat: 0, age: 0 });

  resizeStorm3d();
  storm3d.particles.forEach(seedParticle);
  bindStorm3dInteractions();
  window.addEventListener('resize', resizeStorm3d);
  if ('ResizeObserver' in window) {
    new ResizeObserver(resizeStorm3d).observe(storm3d.canvas);
  }

  storm3d.ready = true;
  if (storm3d.pendingState) updateStorm3dScene(storm3d.pendingState);
  else resetStorm3dScene();
  animateStorm3d();
}
function formatAnalysis(state) {
  if (state.selectedFactors.length === 0) {
    return '카드도 안 고르고 그냥 돌렸네요? 기본 조건으로 대충 계산해 줬어요.';
  }

  const selectedNames = state.selectedFactors.map((factor) => factor.label).join(', ');
  const contradiction = has('sst') && has('coldWater')
    ? ' 따뜻한 바다랑 찬 바다를 같이 골라서 서로 깎아먹었어요. 욕심이 과했네요?'
    : '';

  return `고른 카드: ${selectedNames}. 결과는 위 지도와 점수로 확인하세요!${contradiction}`;
}

function formatSelectionPrompt() {
  const selectedFactors = getSelectedFactors();

  if (selectedFactors.length === 0) {
    return '카드를 선택한 뒤 결과 시뮬레이션을 실행하세요. 선택 중에는 예측 수치를 공개하지 않습니다.';
  }

  const selectedNames = selectedFactors.map((factor) => factor.label).join(', ');
  return `선택 카드 ${selectedFactors.length}개: ${selectedNames}. 결과를 보려면\n옆의 결과 시뮬레이션 버튼을 누르세요.`;
}

function renderMetrics(state) {
  const root = document.documentElement;
  root.style.setProperty('--power', `${state.power}%`);
  root.style.setProperty('--damage', `${state.koreaDamage}%`);
  root.style.setProperty('--storm-scale', `${(0.76 + state.power / 115).toFixed(2)}`);
  root.style.setProperty('--storm-speed', `${Math.max(3.2, 10.8 - state.power / 10).toFixed(2)}s`);
  root.style.setProperty('--wind-alpha', `${(0.15 + state.power / 145).toFixed(2)}`);
  root.style.setProperty('--impact-scale', `${(0.62 + state.koreaDamage / 92).toFixed(2)}`);
  root.style.setProperty('--orbit-outer', `${(78 + state.power * 0.19).toFixed(1)}%`);
  root.style.setProperty('--orbit-middle', `${(58 + state.power * 0.17).toFixed(1)}%`);
  root.style.setProperty('--orbit-inner', `${(39 + state.power * 0.13).toFixed(1)}%`);
  root.style.setProperty('--rain-alpha-a', `${Math.min(0.86, 0.14 + state.power / 170).toFixed(2)}`);
  root.style.setProperty('--rain-alpha-b', `${Math.min(0.58, 0.06 + state.power / 260).toFixed(2)}`);
  root.style.setProperty('--impact-opacity', `${Math.min(0.95, 0.2 + state.koreaDamage / 130).toFixed(2)}`);

  const powerLabel = getPowerLabel(state.power);
  const damageLabel = getDamageLabel(state.koreaDamage);

  el.powerValue.textContent = state.power;
  el.powerLabel.textContent = powerLabel;
  el.intensityMetric.textContent = `${state.power} / 100`;
  el.damageMetric.textContent = `${state.koreaDamage} / 100 · ${damageLabel}`;
  el.scoreMetric.textContent = `${state.score}점`;
  el.analysisBox.textContent = formatAnalysis(state);

  document.querySelectorAll('.factor-button').forEach((button) => {
    const isPressed = selected.has(button.dataset.factorId);
    button.setAttribute('aria-pressed', String(isPressed));
  });
}

function renderSelectionState() {
  document.querySelectorAll('.factor-button').forEach((button) => {
    const isPressed = selected.has(button.dataset.factorId);
    button.setAttribute('aria-pressed', String(isPressed));
  });

  el.analysisBox.textContent = formatSelectionPrompt();
}

function renderIdleMetrics() {
  const root = document.documentElement;
  root.style.setProperty('--power', '0%');
  root.style.setProperty('--damage', '0%');
  root.style.setProperty('--storm-scale', '0.72');
  root.style.setProperty('--storm-speed', '10.8s');
  root.style.setProperty('--wind-alpha', '0.12');
  root.style.setProperty('--impact-scale', '0.58');
  root.style.setProperty('--orbit-outer', '72%');
  root.style.setProperty('--orbit-middle', '54%');
  root.style.setProperty('--orbit-inner', '38%');
  root.style.setProperty('--rain-alpha-a', '0.10');
  root.style.setProperty('--rain-alpha-b', '0.04');
  root.style.setProperty('--impact-opacity', '0.16');

  el.powerValue.textContent = '--';
  el.powerLabel.textContent = '대기 중';
  el.intensityMetric.textContent = '시뮬레이션 전';
  el.damageMetric.textContent = '시뮬레이션 전';
  el.scoreMetric.textContent = '--점';
}

function clearSimulationResult() {
  el.resultScreen.hidden = true;
  el.riskList.innerHTML = '';
  el.answerReview.innerHTML = '';
  renderIdleMetrics();
  resetStorm3dScene();
}

function escapeHtml(text) {
  return String(text).replace(/[&<>]/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[c]));
}

function renderAnswerReview(state) {
  if (state.selectedFactors.length === 0) {
    el.answerReview.innerHTML = '<strong>풀이: 내 선택이 태풍을 어떻게 바꿨을까?</strong><p>고른 카드가 없어요. 카드를 골라 다시 시뮬레이션하면, 각 선택이 태풍을 키우거나 약하게 만드는 과정을 단계별로 펼쳐 볼 수 있어요.</p>';
    return;
  }

  const items = state.selectedFactors.map((factor, index) => {
    const learn = FACTOR_LEARN[factor.id] || { chain: [factor.summary], impacts: [] };
    const isWeak = factor.type === 'weakness';
    const answer = isWeak ? '약화 카드' : '강화 카드';
    const arrow = isWeak ? '태풍을 약하게' : '태풍을 강하게';
    const steps = learn.chain.map((step, i) => {
      const sep = i < learn.chain.length - 1 ? '<i class="learn-arrow" aria-hidden="true">↓</i>' : '';
      return `<span class="learn-step">${escapeHtml(step)}</span>${sep}`;
    }).join('');
    const impacts = learn.impacts.length
      ? `<div class="learn-impacts">${learn.impacts.map((t) => `<span class="learn-chip ${isWeak ? 'is-down' : 'is-up'}">${escapeHtml(t)}</span>`).join('')}</div>`
      : '';
    return `
      <details class="learn-item ${isWeak ? 'is-weak' : 'is-strong'}"${index === 0 ? ' open' : ''}>
        <summary>
          <span class="learn-ico">${factor.icon}</span>
          <span class="learn-name">${escapeHtml(factor.label)}</span>
          <span class="learn-tag ${isWeak ? 'is-down' : 'is-up'}">${answer} · ${arrow}</span>
        </summary>
        <div class="learn-body">
          <div class="learn-chain">${steps}</div>
          ${impacts}
        </div>
      </details>`;
  }).join('');

  const synergyLine = state.synergies.length
    ? `<p class="learn-extra"><strong>같이 골라서 생긴 효과:</strong> ${state.synergies.map((item) => `${escapeHtml(item.label)}(${item.value > 0 ? '+' : ''}${item.value})`).join(', ')}</p>`
    : '<p class="learn-extra">이번 조합에는 카드끼리 겹쳐 생기는 추가 효과는 없었어요.</p>';

  const top = state.selectedFactors.reduce((a, b) => (Math.abs(b.weight) > Math.abs(a.weight) ? b : a));
  const riskNames = { windRisk: '강풍', rainRisk: '호우', surgeRisk: '해안' };
  const topRiskKey = ['windRisk', 'rainRisk', 'surgeRisk'].reduce((a, b) => (state[b] > state[a] ? b : a));

  let tip;
  if (state.koreaDamage >= 62) tip = '피해를 줄이고 싶다면 약화 카드(육지 상륙·강한 연직 시어·건조 공기·차가운 해수)를 더 넣어 보세요. 어떤 카드가 가장 크게 깎는지 비교하면 원리가 보여요.';
  else if (state.koreaDamage <= 22) tip = '아주 잘 막았어요! 이번엔 강화 카드를 넣어 태풍이 어떻게 세지는지 반대로 실험해 보면 더 잘 이해돼요.';
  else tip = '약화 카드를 한두 개 더 넣으면 피해가 더 줄어요. 강화 카드를 빼는 것도 방법이에요.';

  const story = `
    <div class="learn-summary">
      <p><strong>한눈에 보기</strong></p>
      <p>이번 판에서 가장 크게 작용한 카드는 <b>${escapeHtml(top.label)}</b>(위력 ${top.weight > 0 ? '+' : ''}${top.weight})였어요.
      그 결과 위험은 <b>${riskNames[topRiskKey]} 위험 ${state[topRiskKey]}/100</b>이 가장 높았어요.</p>
      <p class="learn-formula">대한민국 피해도 = 강풍 ${state.windRisk}×0.46 + 호우 ${state.rainRisk}×0.34 + 해안 ${state.surgeRisk}×0.20 ≈ <b>${state.koreaDamage}/100</b></p>
      <p class="learn-tip">${tip}</p>
    </div>`;

  el.answerReview.innerHTML = `<strong>풀이: 카드를 눌러 원인 → 결과를 펼쳐 보세요</strong>${items}${synergyLine}${story}`;
}

function renderResult(state, shouldFocus = false) {
  const damageLabel = getDamageLabel(state.koreaDamage);
  el.resultScreen.hidden = false;
  el.resultTitle.textContent = `대한민국 피해도: ${damageLabel} (${state.koreaDamage}/100)`;
  el.resultSummary.textContent = `${getDamageTone(state.koreaDamage)} 아래 점수는 학습용 상대점수예요.`;
  el.resultScore.textContent = `${state.score}점`;
  el.resultPower.textContent = `${state.power} / 100`;
  el.resultDamage.textContent = `${state.koreaDamage} / 100`;

  const riskItems = [
    ['강풍 위험', state.windRisk, '중심기압 차와 순환 강도에 가까운 지표입니다.'],
    ['호우 위험', state.rainRisk, '습윤 공기와 하층 수렴이 높을수록 증가합니다.'],
    ['해안 위험', state.surgeRisk, '강한 바람·낮은 기압·해양 열 조건을 단순 반영합니다.'],
  ];

  el.riskList.innerHTML = riskItems.map(([label, value, description]) => `
    <li><strong>${label}: ${value}/100</strong>${description}</li>
  `).join('');
  renderAnswerReview(state);
  updateStorm3dScene(state);

  if (shouldFocus) {
    el.resultScreen.scrollIntoView({ behavior: 'smooth', block: 'start' });
    el.resultScreen.focus({ preventScroll: true });
  }
}

function toggleFactor(id) {
  if (selected.has(id)) {
    selected.delete(id);
  } else {
    selected.add(id);
  }

  clearSimulationResult();
  renderSelectionState();
}

function resetGame() {
  selected.clear();
  clearSimulationResult();
  renderSelectionState();
}

function bindActions() {
  el.simulateButton.addEventListener('click', () => {
    const state = calculateState();
    renderMetrics(state);
    renderResult(state, true);
  });

  el.resetButton.addEventListener('click', resetGame);
}

function init() {
  collectElements();
  renderFactorButtons();
  bindActions();
  renderIdleMetrics();
  renderSelectionState();
  initStorm3dScene();
}

document.addEventListener('DOMContentLoaded', init);
